head.script:
{
  "@context": "https://schema.org",
  "@type": "WebSite",
  "name": "",
  "url": "",
  "description": "VEMS AI - Solusi Cerdas Asisten Koding, Chatbot, dan Integrasi Cloudflare R2 di Blogger.",
  "potentialAction": {
    "@type": "SearchAction",
    "target": "search?q={search_term_string}",
    "query-input": "required name=search_term_string"
  }
}

//
var uri = window.location.toString();
if (uri.indexOf("?m=1","?m=0") > 0) {
    var clean_uri = uri.substring(0, uri.indexOf("?m="));
    window.history.replaceState({}, document.title, clean_uri);
}
//

body.script:
//
    // Kunci API Server Backend VEMS AI
    const workerApiUrl = "https://yyyyyyyy.xxxxxxxxx.workers.dev";

    let authToken = localStorage.getItem("CLOUDFLARE_AUTH_TOKEN") || "";
    let userProfile = null;
    let attachedFileContent = "";
    let currentModel = "Qwen 3"; 
    let currentActiveMenu = "Chats"; 

    // SISTEM MULTI-SESSION
    let allSessions = [];       
    let activeSessionId = "";   

    // Selectors Utama
    const openSidebarBtn = document.getElementById('openSidebarBtn');
    const sidebarOverlay = document.getElementById('sidebarOverlay');
    const sidebarPanel = document.getElementById('sidebarPanel');
    const welcomeState = document.getElementById('welcomeState');
    const chatHistoryState = document.getElementById('chatHistoryState');
    const chatInput = document.getElementById('chatInput');
    const sendBtn = document.getElementById('sendBtn');
    const greetingText = document.getElementById('greetingText');
    const subGreeting = document.getElementById('subGreeting');
    const connectionStatus = document.getElementById('connectionStatus');
    const quickLoginBtn = document.getElementById('quickLoginBtn');

    // Sidebar & Profile Elements
    const sidebarGithubLoginBtn = document.getElementById('sidebarGithubLoginBtn');
    const sidebarLogoutBtn = document.getElementById('sidebarLogoutBtn');
    const sidebarLoginPromptBtn = document.getElementById('sidebarLoginPromptBtn');
    const userProfileName = document.getElementById('userProfileName');
    const userAvatarText = document.getElementById('userAvatarText');
    const recentsListContainer = document.getElementById('recentsListContainer');
    const sidebarNewChatBtn = document.getElementById('sidebarNewChatBtn');
    const proModal = document.getElementById('proModal');

    // Elements untuk Profile Card Dropdown
    const profileCardDropdown = document.getElementById('profileCardDropdown');
    const dropdownAvatar = document.getElementById('dropdownAvatar');
    const dropdownName = document.getElementById('dropdownName');
    const dropdownHandle = document.getElementById('dropdownHandle');
    const dropdownLocation = document.getElementById('dropdownLocation');
    const dropdownBio = document.getElementById('dropdownBio');
    const dropdownStatsContainer = document.getElementById('dropdownStatsContainer');
    const dropdownGithubLink = document.getElementById('dropdownGithubLink');
    const statRepos = document.getElementById('statRepos');
    const statFollowers = document.getElementById('statFollowers');
    const statFollowing = document.getElementById('statFollowing');

    // Views Elements
    const chatView = document.getElementById('chatView');
    const galleryView = document.getElementById('galleryView');
    const menuChatsBtn = document.getElementById('menuChatsBtn');
    const menuGalleryBtn = document.getElementById('menuGalleryBtn');

    // Gallery Storage R2 Elements
    const galleryLockScreen = document.getElementById('galleryLockScreen');
    const lockScreen = document.getElementById('lockScreen');
    const galleryContentArea = document.getElementById('galleryContentArea');
    const galleryEmptyState = document.getElementById('galleryEmptyState');
    const galleryGrid = document.getElementById('galleryGrid');
    const galleryLoader = document.getElementById('galleryLoader');
    const galleryFileInput = document.getElementById('galleryFileInput');
    const dragDropZone = document.getElementById('dragDropZone');

    // File Uploader
    const fileSelectorInput = document.getElementById('fileSelectorInput');
    const attachedFileContainer = document.getElementById('attachedFileContainer');
    const attachedFileName = document.getElementById('attachedFileName');

    // Voice
    const micBtn = document.getElementById('micBtn');
    const voiceModal = document.getElementById('voiceModal');
    const stopVoiceBtn = document.getElementById('stopVoiceBtn');

    // ==================== MARKED & DOMPURIFY CONFIGURATION ====================
    const customRenderer = {
        code(token, infostring, escaped) {
            let codeText = "";
            let lang = "";

            if (typeof token === 'object' && token !== null) {
                codeText = token.text || "";
                lang = token.lang || "";
            } else {
                codeText = token || "";
                lang = infostring || "";
            }

            const cleanLang = (lang || '').match(/\S*/)[0];
            const cleanCode = codeText;
            const blockId = 'code-' + Math.random().toString(36).substr(2, 9);

            const highlighted = cleanLang && hljs.getLanguage(cleanLang) 
                ? hljs.highlight(cleanCode, { language: cleanLang }).value 
                : escapeHtml(cleanCode);

            const hasPreview = cleanLang === 'html' || cleanLang === 'svg';
            const previewBtn = hasPreview 
                ? `<button data-action="preview" data-target="${blockId}" class="px-2 py-1 bg-amber-600/20 hover:bg-amber-600/40 text-amber-400 text-[10px] rounded flex items-center gap-1 transition-all border border-amber-500/20"><i class="fa-solid fa-play text-[9px]"></i> Preview</button>` 
                : '';

            return `
                <div class="my-4 rounded-xl overflow-hidden border border-[#2e2e2a] bg-[#121210] shadow-md">
                    <div class="flex justify-between items-center px-4 py-2 bg-[#1d1d1a] border-b border-[#2e2e2a]/40 text-xs text-gray-400">
                        <span class="font-mono text-[10px] uppercase tracking-wider text-orange-400">${cleanLang || 'plaintext'}</span>
                        <div class="flex items-center gap-2">
                            ${previewBtn}
                            <button data-action="copy" data-target="${blockId}" class="px-2 py-1 bg-[#2d2d2a] hover:bg-[#3d3d3a] text-gray-300 text-[10px] rounded flex items-center gap-1 transition-all border border-[#3d3d3a]/30">
                                <i class="fa-regular fa-copy text-[9px]"></i> Salin
                            </button>
                        </div>
                    </div>
                    <pre class="p-4 overflow-x-auto text-xs leading-relaxed custom-scrollbar"><code id="${blockId}" class="hljs language-${cleanLang || 'plaintext'}">${highlighted}</code></pre>
                    <div id="preview-${blockId}" class="hidden p-4 border-t border-[#2e2e2a]/40 bg-white text-black h-80 overflow-auto rounded-b-xl relative">
                        <div class="absolute top-2 right-2 z-10 flex gap-2">
                            <button data-action="close-preview" data-target="${blockId}" class="bg-red-500 hover:bg-red-600 text-white text-[9px] px-2 py-1 rounded shadow-md"><i class="fa-solid fa-xmark"></i> Tutup</button>
                        </div>
                        <iframe id="iframe-${blockId}" class="w-full h-full border-none bg-white"></iframe>
                    </div>
                </div>
            `;
        }
    };

    marked.use({ renderer: customRenderer });

    document.addEventListener('click', (e) => {
        const target = e.target.closest('[data-action]');
        if (!target) return;

        const action = target.getAttribute('data-action');
        const blockId = target.getAttribute('data-target');

        if (action === 'copy') {
            copyCodeBlock(blockId);
        } else if (action === 'preview') {
            previewHtmlCode(target);
        } else if (action === 'close-preview') {
            closePreview(blockId);
        }
    });

    function copyCodeBlock(id) {
        const codeElem = document.getElementById(id);
        if (!codeElem) return;
        const textToCopy = codeElem.innerText;

        const tempTextArea = document.createElement('textarea');
        tempTextArea.value = textToCopy;
        document.body.appendChild(tempTextArea);
        tempTextArea.select();
        document.execCommand('copy');
        document.body.removeChild(tempTextArea);

        showToast("Kode berhasil disalin ke clipboard!");
    }

    function previewHtmlCode(buttonElement) {
        const blockContainer = buttonElement.closest('.my-4');
        const codeBlock = blockContainer.querySelector('code');
        const iframe = blockContainer.querySelector('iframe');
        const previewSection = blockContainer.querySelector('[id^="preview-"]');

        if (!codeBlock || !iframe || !previewSection) return;

        const codeSource = codeBlock.innerText;
        previewSection.classList.remove('hidden');

        const iframeDoc = iframe.contentDocument || iframe.contentWindow.document;
        iframeDoc.open();
        iframeDoc.write(codeSource);
        iframeDoc.close();

        showToast("Live HTML Preview diaktifkan.");
    }

    function closePreview(blockId) {
        const previewSection = document.getElementById(`preview-${blockId}`);
        if (previewSection) {
            previewSection.classList.add('hidden');
        }
    }

    // ==================== MAIN SERVICE LOGIC ====================
    function checkUrlAuthToken() {
        const params = new URLSearchParams(window.location.search);
        const urlToken = params.get("token");
        if (urlToken) {
            localStorage.setItem("CLOUDFLARE_AUTH_TOKEN", urlToken);
            authToken = urlToken;
            window.history.replaceState({}, document.title, window.location.pathname);
            showToast("Autentikasi Berhasil! Sesi VEMS AI Anda aktif.");
        }
    }

    function adjustGreeting() {
        const hour = new Date().getHours();
        let name = userProfile ? userProfile.name : "Anonymous";
        let message = "";

        if (hour >= 5 && hour < 12) {
            message = `Good morning, ${name}!`;
        } else if (hour >= 12 && hour < 17) {
            message = `Good afternoon, ${name}!`;
        } else if (hour >= 17 && hour < 21) {
            message = `Good evening, ${name}!`;
        } else {
            message = `Up late, ${name}?`;
        }

        greetingText.textContent = message;
    }

    async function fetchUserProfile() {
        connectionStatus.className = "w-2 h-2 rounded-full bg-yellow-500 animate-pulse";
        try {
            const response = await fetch(`${workerApiUrl}/api/auth/me`, {
                headers: { "Authorization": `Bearer ${authToken}` }
            });
            const data = await response.json();

            if (data.authenticated && data.user) {
                userProfile = data.user;

                userProfileName.textContent = userProfile.name;
                userAvatarText.innerHTML = `<img src="${userProfile.avatar}" class="w-full h-full object-cover" alt="User Avatar" />`;

                dropdownAvatar.innerHTML = `<img src="${userProfile.avatar}" class="w-full h-full object-cover" alt="Dropdown Avatar" />`;
                dropdownName.textContent = userProfile.name;
                dropdownHandle.textContent = `@${userProfile.login}`;
                dropdownLocation.innerHTML = `<i class="fa-solid fa-location-dot text-[9px] mr-1 text-red-400/80"></i>${userProfile.location || "Earth"}`;
                dropdownBio.textContent = userProfile.bio ? `"${userProfile.bio}"` : '"No bio available on GitHub."';

                statRepos.textContent = userProfile.public_repos || 0;
                statFollowers.textContent = userProfile.followers || 0;
                statFollowing.textContent = userProfile.following || 0;
                dropdownGithubLink.href = userProfile.html_url || "https://github.com";

                sidebarGithubLoginBtn.classList.add('hidden');
                sidebarLogoutBtn.classList.remove('hidden');
                sidebarLoginPromptBtn.classList.add('hidden');
                quickLoginBtn.classList.add('hidden');

                connectionStatus.className = "w-2 h-2 rounded-full bg-green-500";
                subGreeting.textContent = `Server VEMS AI terhubung secara aman di cloud.`;

                galleryLockScreen.classList.add('hidden');
                galleryContentArea.classList.remove('hidden');
                lockScreen.classList.remove('hidden');

                await loadHistoryFromKV();

                if (currentActiveMenu === "Gallery") {
                    await loadR2FilesFromCloud();
                }
            } else {
                applyAnonymousUi();
            }
        } catch (err) {
            console.error("VEMS Server Offline / Gangguan Jaringan:", err);
            connectionStatus.className = "w-2 h-2 rounded-full bg-red-500 animate-pulse";
            subGreeting.textContent = "Gagal menghubungi VEMS Server. Coba muat ulang halaman.";
            applyAnonymousUi();
        }
        adjustGreeting();
    }

    function applyAnonymousUi() {
        userProfile = null;
        userProfileName.textContent = "Anonymous";
        userAvatarText.innerHTML = "AN";

        dropdownAvatar.innerHTML = "AN";
        dropdownName.textContent = "Anonymous User";
        dropdownHandle.textContent = "@anonymous";
        dropdownLocation.innerHTML = `<i class="fa-solid fa-location-dot text-[9px] mr-1 text-red-400/80"></i>Earth`;
        dropdownBio.textContent = '"Menggunakan sistem koding VEMS AI asisten secara anonim tanpa integrasi awan."';
        statRepos.textContent = "0";
        statFollowers.textContent = "0";
        statFollowing.textContent = "0";
        dropdownGithubLink.href = "https://github.com";

        sidebarGithubLoginBtn.classList.remove('hidden');
        sidebarLogoutBtn.classList.add('hidden');
        sidebarLoginPromptBtn.classList.remove('hidden');
        quickLoginBtn.classList.remove('hidden');
        subGreeting.textContent = "Gunakan secara anonim atau masuk via GitHub untuk mencatat histori di KV Cloud.";

        galleryLockScreen.classList.remove('hidden');
        galleryContentArea.classList.add('hidden');
        lockScreen.classList.add('hidden');

        loadLocalHistoryOnly();
    }

    function toggleProfileDropdown(event) {
        event.stopPropagation();
        profileCardDropdown.classList.toggle('hidden');
    }

    document.addEventListener('click', (event) => {
        if (!profileCardDropdown.classList.contains('hidden') && !event.target.closest('#profileCardDropdown') && !event.target.closest('#userProfileTrigger')) {
            profileCardDropdown.classList.add('hidden');
        }
    });

    function changeMenu(menu) {
        currentActiveMenu = menu;
        closeSidebar();

        menuChatsBtn.className = "w-full flex items-center gap-3 py-2 px-3 rounded-lg hover:bg-[#1d1d1a] transition-colors text-sm text-left text-gray-300";
        menuChatsBtn.querySelector('svg').className = "text-gray-400";
        menuGalleryBtn.className = "w-full flex items-center gap-3 py-2 px-3 rounded-lg hover:bg-[#1d1d1a] transition-colors text-sm text-left text-gray-300";
        menuGalleryBtn.querySelector('i').className = "fa-regular fa-images text-[14px] text-gray-400";

        if (menu === "Chats") {
            chatView.classList.remove('hidden');
            galleryView.classList.add('hidden');

            menuChatsBtn.className = "w-full flex items-center gap-3 py-2 px-3 rounded-lg bg-[#1d1d1a] hover:bg-[#1d1d1a] transition-colors text-sm text-left";
            menuChatsBtn.querySelector('svg').className = "text-orange-400";
        } else if (menu === "Gallery") {
            chatView.classList.add('hidden');
            galleryView.classList.remove('hidden');

            menuGalleryBtn.className = "w-full flex items-center gap-3 py-2 px-3 rounded-lg bg-[#1d1d1a] hover:bg-[#1d1d1a] transition-colors text-sm text-left";
            menuGalleryBtn.querySelector('i').className = "fa-regular fa-images text-[14px] text-orange-400";

            if (userProfile) {
                loadR2FilesFromCloud();
            }
        }
    }

    // ==================== GALERI R2 INTERACTION LOGIC ====================
    function triggerGalleryUpload() {
        galleryFileInput.click();
    }

    async function loadR2FilesFromCloud() {
        galleryLoader.classList.remove('hidden');
        galleryEmptyState.classList.add('hidden');
        galleryGrid.classList.add('hidden');

        try {
            const response = await fetch(`${workerApiUrl}/api/media`, {
                headers: { "Authorization": `Bearer ${authToken}` }
            });
            const data = await response.json();
            galleryLoader.classList.add('hidden');

            if (data.success && data.files) {
                renderGalleryGrid(data.files);
            } else {
                galleryEmptyState.classList.remove('hidden');
            }
        } catch (err) {
            galleryLoader.classList.add('hidden');
            galleryEmptyState.classList.remove('hidden');
            showToast("Gagal memuat galeri berkas R2.");
        }
    }

    function renderGalleryGrid(files) {
        galleryGrid.innerHTML = '';

        if (files.length === 0) {
            galleryEmptyState.classList.remove('hidden');
            galleryGrid.classList.add('hidden');
            return;
        }

        galleryEmptyState.classList.add('hidden');
        galleryGrid.classList.remove('hidden');

        files.forEach((file) => {
            const card = document.createElement('div');
            card.className = "bg-[#1e1e1c] border border-[#2e2e2a]/60 hover:border-[#d97753]/50 rounded-2xl overflow-hidden p-3 transition-all flex flex-col justify-between shadow-sm group";

            const formattedSize = formatBytes(file.size);
            const fileDate = new Date(file.uploaded).toLocaleDateString("id-ID", {
                day: "numeric", month: "short", year: "numeric"
            });

            let visualThumbnail = '';
            if (file.fileType === "image") {
                visualThumbnail = `<div class="w-full h-32 rounded-xl bg-[#121210] overflow-hidden mb-3 relative flex items-center justify-center">
                    <img src="${file.httpUrl}" class="w-full h-full object-cover group-hover:scale-105 duration-300" alt="Visual Asset" />
                </div>`;
            } else if (file.fileType === "audio") {
                visualThumbnail = `<div class="w-full h-32 rounded-xl bg-orange-500/5 text-orange-400 flex flex-col items-center justify-center mb-3">
                    <i class="fa-regular fa-circle-play text-3xl mb-1 opacity-80"></i>
                    <span class="text-[9px] font-semibold uppercase tracking-widest opacity-60">Audio File</span>
                </div>`;
            } else if (file.fileType === "document") {
                visualThumbnail = `<div class="w-full h-32 rounded-xl bg-amber-500/5 text-amber-400 flex flex-col items-center justify-center mb-3">
                    <i class="fa-regular fa-file-lines text-3xl mb-1 opacity-80"></i>
                    <span class="text-[9px] font-semibold uppercase tracking-widest opacity-60">Dokumen</span>
                </div>`;
            } else {
                visualThumbnail = `<div class="w-full h-32 rounded-xl bg-[#2e2e2a]/30 text-gray-400 flex flex-col items-center justify-center mb-3">
                    <i class="fa-solid fa-paperclip text-3xl mb-1 opacity-60"></i>
                    <span class="text-[9px] font-semibold uppercase tracking-widest opacity-60">Berkas</span>
                </div>`;
            }

            card.innerHTML = `
                <div>
                    ${visualThumbnail}
                    <h4 class="text-xs font-bold text-white truncate px-1" title="${file.name}">${escapeHtml(file.name)}</h4>
                    <div class="flex justify-between items-center text-[10px] text-gray-500 px-1 mt-1.5">
                        <span>${formattedSize}</span>
                        <span>${fileDate}</span>
                    </div>
                </div>
                <div class="flex gap-2 mt-4 pt-2.5 border-t border-[#2e2e2a]/40">
                    <a href="${file.httpUrl}" target="_blank" class="flex-1 py-1.5 bg-[#2d2d2a] hover:bg-[#3d3d3a] text-gray-200 rounded-lg text-[10px] font-medium flex items-center justify-center gap-1 transition-all">
                        <i class="fa-solid fa-download"></i> Unduh
                    </a>
                    <button onclick="deleteGalleryR2File('${file.key}')" class="px-2.5 py-1.5 bg-red-500/10 hover:bg-red-500/20 text-red-400 hover:text-red-300 rounded-lg text-[10px] font-medium transition-all" title="Hapus berkas">
                        <i class="fa-regular fa-trash-can"></i>
                    </button>
                </div>
            `;

            galleryGrid.appendChild(card);
        });
    }

    async function handleGalleryR2Upload(event) {
        const file = event.target.files[0];
        if (!file) return;

        await executeR2UploadPipeline(file);
    }

    async function executeR2UploadPipeline(file) {
        const formData = new FormData();
        formData.append("file", file);

        showToast("Mengunggah berkas ke R2...");

        try {
            const response = await fetch(`${workerApiUrl}/api/media/upload`, {
                method: "POST",
                headers: { "Authorization": `Bearer ${authToken}` },
                body: formData
            });
            const data = await response.json();

            if (response.ok && data.success) {
                showToast("Berkas sukses ditambahkan ke R2!");
                loadR2FilesFromCloud();
            } else {
                showToast("Sesi kedaluwarsa. Silakan masuk kembali.");
            }
        } catch (err) {
            showToast("Gagal melakukan upload.");
        }
    }

    async function deleteGalleryR2File(fileKey) {
        if (confirm("Apakah Anda yakin ingin menghapus berkas ini secara permanen dari Cloudflare R2 Storage?")) {
            showToast("Menghapus berkas...");
            try {
                const response = await fetch(`${workerApiUrl}/api/media?key=${encodeURIComponent(fileKey)}`, {
                    method: "DELETE",
                    headers: { "Authorization": `Bearer ${authToken}` }
                });
                const data = await response.json();

                if (response.ok && data.success) {
                    showToast("Berkas berhasil terhapus!");
                    loadR2FilesFromCloud();
                } else {
                    showToast("Aksi gagal: Sesi tidak sah.");
                }
            } catch (err) {
                showToast("Kesalahan sistem saat menghapus berkas.");
            }
        }
    }

    function formatBytes(bytes, decimals = 1) {
        if (bytes === 0) return '0 Bytes';
        const k = 1024;
        const dm = decimals < 0 ? 0 : decimals;
        const sizes = ['Bytes', 'KB', 'MB', 'GB'];
        const i = Math.floor(Math.log(bytes) / Math.log(k));
        return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i];
    }

    ['dragenter', 'dragover', 'dragleave', 'drop'].forEach(eventName => {
        dragDropZone.addEventListener(eventName, preventDefaults, false);
    });

    function preventDefaults (e) {
        e.preventDefault();
        e.stopPropagation();
    }

    ['dragenter', 'dragover'].forEach(eventName => {
        dragDropZone.addEventListener(eventName, () => {
            dragDropZone.className = "border-2 border-dashed border-[#d97753] bg-[#d97753]/5 p-8 rounded-2xl text-center cursor-pointer transition-all mb-8 flex flex-col items-center justify-center";
        }, false);
    });

    ['dragleave', 'drop'].forEach(eventName => {
        dragDropZone.addEventListener(eventName, () => {
            dragDropZone.className = "border-2 border-dashed border-[#2e2e2a] hover:border-[#d97753]/60 bg-[#121210]/20 p-8 rounded-2xl text-center cursor-pointer transition-all mb-8 flex flex-col items-center justify-center";
        }, false);
    });

    dragDropZone.addEventListener('drop', (e) => {
        const dt = e.dataTransfer;
        const files = dt.files;
        if (files.length > 0) {
            executeR2UploadPipeline(files[0]);
        }
    }, false);

    dragDropZone.addEventListener('click', () => {
        triggerGalleryUpload();
    });

    // ==================== MULTI-SESSION LOGIC ====================
    async function loadHistoryFromKV() {
        try {
            const res = await fetch(`${workerApiUrl}/api/chat/history`, {
                headers: { "Authorization": `Bearer ${authToken}` }
            });
            const data = await res.json();
            if (data.success && data.sessions) {
                allSessions = data.sessions;
                renderRecentsList();
            }
        } catch (err) {
            console.error("Gagal sinkronisasi data dari KV:", err);
        }
    }

    async function saveSessionsToKV() {
        if (!userProfile) {
            localStorage.setItem("VEMS_SESSIONS_LOCAL", JSON.stringify(allSessions));
            renderRecentsList();
            return;
        }
        try {
            await fetch(`${workerApiUrl}/api/chat/history`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${authToken}`
                },
                body: JSON.stringify({ sessions: allSessions })
            });
            renderRecentsList();
        } catch (err) {
            console.error("Gagal mengunggah sesi chat ke KV:", err);
        }
    }

    function loadLocalHistoryOnly() {
        const raw = localStorage.getItem("VEMS_SESSIONS_LOCAL");
        if (raw) {
            allSessions = JSON.parse(raw);
            renderRecentsList();
        }
    }

    function renderRecentsList() {
        recentsListContainer.innerHTML = '';

        if (allSessions.length === 0) {
            recentsListContainer.innerHTML = `<span class="text-[10px] text-[#575752] italic pl-1">Belum ada percakapan terbaru</span>`;
            return;
        }

        allSessions.forEach((session) => {
            const button = document.createElement('button');
            const isActive = session.sessionId === activeSessionId;
            button.className = `w-full text-left px-3 py-2 rounded-lg text-xs transition-all overflow-hidden text-ellipsis whitespace-nowrap block ${isActive ? 'bg-[#1d1d1a] text-white border-l-2 border-[#d97753]' : 'text-gray-300 hover:bg-[#1d1d1a] hover:text-white'}`;
            button.innerHTML = `<i class="fa-regular fa-comment ${isActive ? 'text-[#d97753]' : 'text-gray-500'} mr-2 text-[10px]"></i>${escapeHtml(session.title)}`;
            button.title = session.title;
            button.addEventListener('click', () => {
                restoreChatSession(session.sessionId);
            });
            recentsListContainer.appendChild(button);
        });
    }

    function restoreChatSession(sessionId) {
        activeSessionId = sessionId;
        closeSidebar();
        changeMenu('Chats'); 

        const targetSession = allSessions.find(s => s.sessionId === sessionId);
        if (!targetSession) return;

        welcomeState.classList.add('opacity-0');
        setTimeout(() => {
            welcomeState.style.display = 'none';
            chatHistoryState.innerHTML = '';
            chatHistoryState.classList.remove('hidden');

            targetSession.messages.forEach(msg => {
                appendMessageBubble(msg.content, msg.role);
            });

            renderRecentsList(); 
            showToast("Sesi obrolan dipulihkan.");
        }, 200);
    }

    function initiateGithubAuth() {
        showToast("Menghubungkan ke GitHub...");
        window.location.href = `${workerApiUrl}/api/auth/github`;
    }

    async function logoutSession() {
        if (confirm("Apakah Anda yakin ingin keluar dari VEMS AI?")) {
            try {
                await fetch(`${workerApiUrl}/api/auth/logout`, {
                    method: "POST",
                    headers: { "Authorization": `Bearer ${authToken}` }
                });
            } catch (e) {}
            localStorage.removeItem("CLOUDFLARE_AUTH_TOKEN");
            authToken = "";
            showToast("Sesi akun dinonaktifkan.");
            closeSidebar();
            profileCardDropdown.classList.add('hidden');
            fetchUserProfile();
        }
    }

    async function clearLocalHistory() {
        if (confirm("Bersihkan seluruh riwayat obrolan Anda?")) {
            if (userProfile) {
                try {
                    await fetch(`${workerApiUrl}/api/chat/history`, {
                        method: "DELETE",
                        headers: { "Authorization": `Bearer ${authToken}` }
                    });
                } catch (e) {}
            }
            localStorage.removeItem("VEMS_SESSIONS_LOCAL");
            allSessions = [];
            activeSessionId = "";
            startNewChat();
            showToast("Riwayat obrolan dibersihkan.");
        }
    }

    function triggerFileUpload() {
        fileSelectorInput.click();
    }

    async function handleR2FileUpload(event) {
        const file = event.target.files[0];
        if (!file) return;

        const formData = new FormData();
        formData.append("file", file);

        showToast("Mengunggah berkas ke VEMS R2 Storage...");

        try {
            const response = await fetch(`${workerApiUrl}/api/media/upload`, {
                method: "POST",
                headers: { "Authorization": `Bearer ${authToken}` },
                body: formData
            });
            const data = await response.json();

            if (data.success || response.ok) {
                showToast("Dokumen berhasil dilampirkan!");
                attachedFileName.textContent = file.name;
                attachedFileContainer.classList.remove('hidden');

                const reader = new FileReader();
                reader.onload = function(e) {
                    attachedFileContent = e.target.result;
                };
                reader.readAsText(file);
            } else {
                showToast(`Akses Ditolak: Silakan login via GitHub terlebih dahulu.`);
            }
        } catch (err) {
            showToast("Gagal mengunggah berkas ke Cloud R2.");
        }
    }

    function removeAttachedFile() {
        attachedFileContainer.classList.add('hidden');
        attachedFileContent = "";
        fileSelectorInput.value = "";
        showToast("Lampiran berkas dihapus.");
    }

    async function sendMessage() {
        const text = chatInput.value.trim();
        if (!text) return;

        if (!activeSessionId) {
            activeSessionId = 'session-' + Math.random().toString(36).substr(2, 9);
            allSessions.unshift({
                sessionId: activeSessionId,
                title: text.substring(0, 30) + (text.length > 30 ? '...' : ''),
                messages: []
            });
        }

        const currentSession = allSessions.find(s => s.sessionId === activeSessionId);

        if (welcomeState.style.display !== 'none') {
            welcomeState.classList.add('opacity-0');
            setTimeout(() => {
                welcomeState.style.display = 'none';
                chatHistoryState.classList.remove('hidden');
            }, 200);
        }

        appendMessageBubble(text, 'user');
        currentSession.messages.push({ role: "user", content: text });

        chatInput.value = '';
        chatInput.style.height = 'auto';

        const typingIndicator = appendTypingIndicator();

        try {
            const response = await fetch(`${workerApiUrl}/`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${authToken}`
                },
                body: JSON.stringify({
                    message: text,
                    fileContext: attachedFileContent,
                    model: currentModel, 
                    history: currentSession.messages
                })
            });

            const data = await response.json();
            typingIndicator.remove();

            if (response.ok && data.success && data.response) {
                appendMessageBubble(data.response, 'assistant');
                currentSession.messages.push({ role: "assistant", content: data.response });

                saveSessionsToKV();

                if (attachedFileContent) {
                    removeAttachedFile();
                }
            } else {
                appendMessageBubble(`Gagal menghubungkan AI: ${data.error || "Kesalahan server"}`, 'assistant');
            }
        } catch (err) {
            if (typeof typingIndicator !== 'undefined' && typingIndicator) {
                typingIndicator.remove();
            }
            appendMessageBubble("Koneksi gagal atau model sibuk. Silakan coba lagi.", 'assistant');
        }
    }

    function appendMessageBubble(text, sender) {
        const wrapper = document.createElement('div');
        wrapper.className = `flex ${sender === 'user' ? 'justify-end' : 'justify-start'} w-full transition-opacity duration-300`;

        const isUser = sender === 'user';
        wrapper.innerHTML = isUser
            ? `<div class="max-w-[85%] sm:max-w-[75%] bg-[#22221f] text-[#e2e2d9] border border-[#2e2e2a] px-4 py-3 rounded-2xl rounded-tr-sm text-sm leading-relaxed whitespace-pre-wrap shadow-sm">${escapeHtml(text)}</div>`
            : `<div class="flex gap-4 w-full">
                <div class="w-8 h-8 rounded-full bg-[#d97753]/15 flex items-center justify-center flex-shrink-0 text-[#d97753] border border-[#d97753]/30">
                    <svg width="15" height="15" viewBox="0 0 64 64" fill="none">
                        <path d="M32 4C32 4 33.5 18 36.5 21C39.5 24 53.5 24 53.5 24C53.5 24 39.5 26 36.5 29C33.5 32 32 46 32 46C32 46 30.5 32 27.5 29C24.5 26 10.5 24 10.5 24C10.5 24 24.5 24 27.5 21C30.5 18 32 4 32 4Z" fill="currentColor"/>
                    </svg>
                </div>
                <div class="text-[#e2e2d9] text-[14px] leading-relaxed flex-1 overflow-hidden">
                    <p class="font-bold text-[10px] text-orange-400 tracking-widest mb-1 uppercase">${currentModel}</p>
                    <div class="markdown-body text-gray-200">${formatText(text)}</div>
                </div>
               </div>`;

        chatHistoryState.appendChild(wrapper);
        scrollChat();
    }

    function appendTypingIndicator() {
        const bubble = document.createElement('div');
        bubble.className = "flex justify-start w-full";
        bubble.innerHTML = `
            <div class="flex gap-4 items-center">
                <div class="w-8 h-8 rounded-full bg-[#d97753]/15 flex items-center justify-center flex-shrink-0 text-[#d97753] border border-[#d97753]/30">
                    <svg width="15" height="15" viewBox="0 0 64 64" fill="none">
                        <path d="M32 4C32 4 33.5 18 36.5 21C39.5 24 53.5 24 53.5 24C53.5 24 39.5 26 36.5 29C33.5 32 32 46 32 46C32 46 30.5 32 27.5 29C24.5 26 10.5 24 10.5 24C10.5 24 24.5 24 27.5 21C30.5 18 32 4 32 4Z" fill="currentColor"/>
                    </svg>
                </div>
                <div class="flex gap-1 items-center bg-[#22221f]/40 px-3 py-2 rounded-lg">
                    <span class="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce"></span>
                    <span class="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style="animation-delay: 0.15s"></span>
                    <span class="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style="animation-delay: 0.3s"></span>
                </div>
            </div>
        `;
        chatHistoryState.appendChild(bubble);
        scrollChat();
        return bubble;
    }

    function scrollChat() {
        const chatArea = document.getElementById('chatArea');
        if (chatArea) {
            chatArea.scrollTo({ top: chatArea.scrollHeight, behavior: 'smooth' });
        }
    }

    function escapeHtml(text) {
        return text.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
    }

    function formatText(text) {
        const rawHtml = marked.parse(text);
        const cleanHtml = DOMPurify.sanitize(rawHtml, {
            ADD_TAGS: ['iframe', 'button', 'span', 'i'],
            ADD_ATTR: ['id', 'class', 'target', 'frameborder', 'src', 'width', 'height', 'data-action', 'data-target'],
            FORCE_BODY: true
        });
        return cleanHtml;
    }

    // Pemilih Model AI
    const modelSelectorBtn = document.getElementById('modelSelectorBtn');
    const modelDropdown = document.getElementById('modelDropdown');
    const selectedModel = document.getElementById('selectedModel');

    modelSelectorBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        modelDropdown.classList.toggle('hidden');
    });
    document.addEventListener('click', () => {
        modelDropdown.classList.add('hidden');
    });
    function selectModel(name) {
        currentModel = name;
        selectedModel.textContent = name;
        showToast(`Model beralih ke: ${name}`);
    }

    // Kontrol Sidebar Panel (Responsive)
    openSidebarBtn.addEventListener('click', () => {
        sidebarOverlay.classList.remove('pointer-events-none', 'opacity-0');
        sidebarPanel.classList.remove('-translate-x-full');
    });

    sidebarOverlay.addEventListener('click', () => {
        closeSidebar();
    });

    function closeSidebar() {
        sidebarOverlay.classList.add('pointer-events-none', 'opacity-0');
        sidebarPanel.classList.add('-translate-x-full');
    }

    sidebarNewChatBtn.addEventListener('click', startNewChat);
    function startNewChat() {
        activeSessionId = ""; 
        closeSidebar();
        changeMenu('Chats'); 
        welcomeState.style.display = 'flex';
        welcomeState.classList.remove('opacity-0');
        chatHistoryState.classList.add('hidden');
        chatHistoryState.innerHTML = '';
        chatInput.value = '';
        chatInput.style.height = 'auto';
        renderRecentsList();
        showToast("Memulai obrolan baru.");
    }

    window.addEventListener('keydown', (e) => {
        if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
            e.preventDefault();
            startNewChat();
        }
    });

    // Modal VEMS Pro
    function openProModal() {
        proModal.classList.remove('hidden');
    }
    function closeProModal() {
        proModal.classList.add('hidden');
    }
    function simulatePro() {
        proModal.classList.add('hidden');
        showToast("Selamat! Akun Anda aktif sebagai VEMS AI Pro.", true);
    }

    // Mic & Voice Simulation
    micBtn.addEventListener('click', () => {
        voiceModal.classList.remove('hidden');
    });
    stopVoiceBtn.addEventListener('click', () => {
        voiceModal.classList.add('hidden');
        chatInput.value = `Berikut adalah contoh halaman web portofolio interaktif sederhana menggunakan Tailwind CSS:\n\n\`\`\`html\n<!DOCTYPE html>\n<html>\n<head>\n  <script src="https://cdn.tailwindcss.com"><\\/script>\n</head>\n<body class="bg-slate-900 text-white flex flex-col items-center justify-center min-h-screen p-4">\n  <div class="max-w-md bg-slate-800 p-6 rounded-2xl shadow-xl text-center border border-slate-700">\n    <h1 class="text-2xl font-bold text-amber-400 mb-2">Halo Dunia!</h1>\n    <p class="text-xs text-slate-300 mb-4">Ini adalah live preview HTML langsung dari asisten koding VEMS AI.</p>\n    <button onclick="alert('Tombol berfungsi!')" class="px-4 py-2 bg-amber-500 hover:bg-amber-600 text-slate-900 text-xs font-bold rounded-xl transition-all shadow-lg shadow-amber-500/20">Klik Saya</button>\n  </div>\n</body>\n</html>\n\`\`\``;
        chatInput.style.height = 'auto';
        chatInput.style.height = (chatInput.scrollHeight) + 'px';
        showToast("Simulasi kode HTML berhasil dibuat!");
    });

    // Toast Notifikasi
    function showToast(msg, isCrown = false) {
        const toast = document.getElementById('toast');
        const toastIcon = document.getElementById('toastIcon');
        const toastMsg = document.getElementById('toastMsg');

        toastMsg.textContent = msg;
        if (isCrown) {
            toast.className = "fixed bottom-6 left-1/2 -translate-x-1/2 bg-[#3a3022] text-[#f59e0b] text-xs py-2.5 px-4 rounded-xl shadow-2xl transition-all duration-300 z-50 border border-[#f59e0b]/30 flex items-center gap-2";
            toastIcon.className = "fa-solid fa-crown text-[#f59e0b]";
        } else {
            toast.className = "fixed bottom-6 left-1/2 -translate-x-1/2 bg-[#2d2d2a] text-[#e2e2d9] text-xs py-2.5 px-4 rounded-xl shadow-2xl transition-all duration-300 z-50 border border-[#3d3d3a] flex items-center gap-2";
            toastIcon.className = "fa-solid fa-circle-check text-green-400";
        }

        toast.classList.remove('translate-y-24', 'opacity-0');
        setTimeout(() => {
            toast.classList.add('translate-y-24', 'opacity-0');
        }, 3000);
    }

    chatInput.addEventListener('input', function() {
        this.style.height = 'auto';
        this.style.height = (this.scrollHeight) + 'px';
    });

    sendBtn.addEventListener('click', sendMessage);

    chatInput.addEventListener('keydown', function(e) {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            sendMessage();
        }
    });

    checkUrlAuthToken();
    fetchUserProfile();
//
